package cn.t8s.filter;

import cn.core.ex.InvalidSettingException;
import cn.core.utils.BufferedImageUtils;
import cn.t8s.BufferedImageComparer;
import cn.t8s.ReflectionUtils;
import cn.t8s.TestUtils;
import org.junit.Assert;
import org.junit.Test;
import java.awt.*;
import java.awt.image.BufferedImage;
import java.io.IOException;

public class MosaicHandlerTest {

    @Test
    public void test_apply_correctUsage() throws IOException {
        MosaicHandler handler = new MosaicHandler.Builder()
                .sideLength(10)
                .startX(55)
                .startY(35)
                .width(60)
                .height(39)
                .build();
        BufferedImage source = TestUtils.getImageFromResource("input/nothing.jpg");

        BufferedImage target = handler.apply(source);

        int sideLength = 10;
        int startX = 55;
        int startY = 35;
        int endX = startX + 60;
        int endY = startY + 39;

        BufferedImage expected = BufferedImageUtils.copy(source, source.getType());
        Graphics g = expected.getGraphics();

        int currentX = startX;
        while (currentX < endX) {
            int nextWidth = Math.min(sideLength, endX - currentX);
            int currentY = startY;
            while (currentY < endY) {
                int nextHeight = Math.min(sideLength, endY - currentY);
                // Manually calculate the center color since ColorUtils is not accessible
                int centerX = currentX + nextWidth / 2;
                int centerY = currentY + nextHeight / 2;
                int centerRgb = source.getRGB(centerX, centerY);
                g.setColor(new Color(centerRgb));
                g.fillRect(currentX, currentY, nextWidth, nextHeight);
                currentY += sideLength;
            }
            currentX += sideLength;
        }
        g.dispose();

        Assert.assertTrue(BufferedImageComparer.isSame(target, expected));
    }

}

