    @Test
    public void testGetGraynessValue_AccurateComputationWithWeights() {
        // Preconditions
        int red = 67;
        int green = 255;
        int blue = 184;
        double redWeight = 0.35;
        double greenWeight = 0.25;
        WeightGrayingStrategy.Builder builder = new WeightGrayingStrategy.Builder();
        builder.redWeight(redWeight);
        builder.greenWeight(greenWeight);
        WeightGrayingStrategy strategy = builder.build();

        // Derive blue weight
        double blueWeight = 1.0 - redWeight - greenWeight;

        // Expected calculation
        double expectedGrayness = redWeight * red + greenWeight * green + blueWeight * blue;
        int expected = (int) expectedGrayness;
        // Ensure within range (though calculation should already be within 0-255)
        if (expected > 255) {
            expected = 255;
        } else if (expected < 0) {
            expected = 0;
        }

        // Actual result
        int actual = strategy.getGraynessValue(red, green, blue);

        // Assertions
        assertEquals("Grayness value should match weighted sum.", expected, actual);
        assertTrue("Grayness value should be within 0 to 255.", actual >= 0 && actual <= 255);
    }
}

