public class MonoColorImageGeneratorTest {

    @Test
    public void test_generate_correctUsage() {
        int width = 50;
        int height = 100;
        Color color = Color.GRAY;
        float alpha = 0.8f;

        MonoColorImageGenerator generator = new MonoColorImageGenerator.Builder()
                .width(width)
                .height(height)
                .color(color)
                .alpha(alpha)
                .build();

        BufferedImage generated = generator.generate();

        Assert.assertEquals(width, generated.getWidth());
        Assert.assertEquals(height, generated.getHeight());

        int rgb = generated.getRGB(0, 0);
        int alphaComponent = (rgb >> 24) & 0xff;
        int expectedAlpha = (int) (alpha * 255);
        Assert.assertEquals(expectedAlpha, alphaComponent);

        int redComponent = (rgb >> 16) & 0xFF;
        int greenComponent = (rgb >> 8) & 0xFF;
        int blueComponent = rgb & 0xFF;
        Assert.assertEquals(color.getRed(), redComponent);
        Assert.assertEquals(color.getGreen(), greenComponent);
        Assert.assertEquals(color.getBlue(), blueComponent);

        BufferedImage reference = BufferedImageUtils.newColoredImage(width, height, alpha, color);
        for (int x = 0; x < width; x++) {
            for (int y = 0; y < height; y++) {
                Assert.assertEquals(reference.getRGB(x, y), generated.getRGB(x, y));
            }
        }
    }

}

